import {REGISTER_SUCCESS, REGISTER_FAIL, LOGIN_SUCCESS, LOGIN_FAIL, LOGOUT} from "../actions/types";

const user = JSON.parse(localStorage.getItem("user"))

const initialState = user ? {isLoggedIn: true, user} : {isLoggedIn: false, user: null}

export default function (state = initialState, action) {
    const {type, payload} = action;
    switch (type) {
        case REGISTER_SUCCESS:
        case LOGIN_SUCCESS:
            localStorage.setItem("user", JSON.stringify(payload.user)); // Lưu vào localStorage
            return {
                ...state,
                isLoggedIn: true,
                user: payload.user,
            };
        case REGISTER_FAIL:
        case LOGIN_FAIL:
            localStorage.removeItem("user"); // Xóa user khỏi localStorage nếu đăng ký/đăng nhập thất bại
            return {
                ...state,
                isLoggedIn: false,
                user: null,
            };
        case LOGOUT:
            localStorage.removeItem("user"); // Xóa user khỏi localStorage khi đăng xuất
            return {
                ...state,
                isLoggedIn: false,
                user: null,
            };
        default:
            return state;
    }
}
